<script lang="ts">import { formatCurrency } from '$lib/utils/format'; let { data, form } = $props();</script>
<section class="card no-print p-6"><p class="text-sm font-medium text-brand-600">Services</p><h1 class="mt-2 text-3xl font-semibold text-slate-900">Create reusable service items</h1></section>
<section class="grid gap-6 xl:grid-cols-[0.9fr_1.1fr]"><form method="POST" action="?/create" data-testid="service-create-form" class="card space-y-4 p-6"><h2 class="text-xl font-semibold text-slate-900">New service</h2><p class="text-sm text-rose-600">{form?.message ?? ''}</p><input class="input" data-testid="service-name" name="name" placeholder="Service name" required /><textarea class="input min-h-28" data-testid="service-description" name="description" placeholder="Description"></textarea><input class="input" data-testid="service-price" name="unitPrice" type="number" min="0" step="0.01" placeholder="Unit price" /><button class="btn-primary" data-testid="service-save" type="submit">Save service</button></form><div class="card p-6"><div class="mb-5 flex items-center justify-between"><h2 class="text-xl font-semibold text-slate-900">Service catalog</h2><p class="text-sm text-slate-500">Use these as invoice shortcuts.</p></div>{#if data.services.length === 0}<div data-testid="services-empty-state" class="rounded-3xl border border-dashed border-slate-200 p-8 text-center text-sm text-slate-500">No services yet. Add your first offering.</div>{:else}<div class="space-y-4">{#each data.services as service}<div class="rounded-3xl border border-slate-100 p-4" data-testid={`service-card-${service.id}`}><div class="flex items-center justify-between gap-4"><div><p class="font-medium text-slate-900">{service.name}</p><p class="mt-1 text-sm text-slate-500">{formatCurrency(service.unitPrice)}</p></div><form method="POST" action="?/delete"><input type="hidden" name="id" value={service.id} /><button class="btn-danger" type="submit">Delete</button></form></div><form method="POST" action="?/update" class="mt-4 grid gap-3"><input type="hidden" name="id" value={service.id} /><input class="input" name="name" value={service.name} required /><textarea class="input min-h-24" name="description">{service.description}</textarea><input class="input" name="unitPrice" type="number" min="0" step="0.01" value={service.unitPrice} /><button class="btn-secondary w-max" data-testid={`service-update-${service.id}`} type="submit">Update</button></form></div>{/each}</div>{/if}</div></section>

